import{_ as a,o as e,c as r,e as t}from"./app.fc9783e2.js";const i={},s=t('<h1 id="java-\u96C6\u5408" tabindex="-1"><a class="header-anchor" href="#java-\u96C6\u5408" aria-hidden="true">#</a> Java \u96C6\u5408</h1><h2 id="list" tabindex="-1"><a class="header-anchor" href="#list" aria-hidden="true">#</a> List</h2><h3 id="arraylist-\u7B80\u4ECB" tabindex="-1"><a class="header-anchor" href="#arraylist-\u7B80\u4ECB" aria-hidden="true">#</a> ArrayList \u7B80\u4ECB</h3><p>ArrayList \u662F\u57FA\u4E8E\u6570\u7EC4\u6765\u5B9E\u73B0\u7684\uFF0C\u5B83\u7684\u6570\u636E\u57DF\u662F\u4E00\u4E2A\u540D\u4E3A elementData \u7684\u6570\u7EC4\uFF0CelementData \u7684\u5BB9\u91CF\u5927\u4E8E\u7B49\u4E8E ArrayList \u5B9E\u9645\u5B58\u50A8\u5143\u7D20\u7684\u4E2A\u6570 size\uFF0C\u5F53 size \u8FBE\u5230 elementData \u7684\u5BB9\u91CF\u65F6\uFF0C\u5C31\u4F1A\u89E6\u53D1 ArrayList \u7684\u6269\u5BB9\u673A\u5236\uFF0C\u4E5F\u5C31\u662F\u521B\u5EFA\u66F4\u5927\u7684\u6570\u7EC4\uFF08\u65B0\u6570\u7EC4\u5BB9\u91CF\u662F\u539F\u6570\u7EC4\u7684 1.5 \u500D\uFF09\u5E76\u5C06\u539F\u6570\u7EC4\u4E2D\u7684\u5143\u7D20\u590D\u5236\u5230\u65B0\u6570\u7EC4\u4E2D\uFF08\u8C03\u7528 Arrays.copyOf \u65B9\u6CD5\u8FDB\u884C\u590D\u5236\uFF09\u3002\u6B64\u5916\uFF0CelementData \u88AB transient \u4FEE\u9970\uFF0C\u5E8F\u5217\u5316\u65F6\u4EC5\u5E8F\u5217\u5316\u771F\u6B63\u6709\u5B9E\u9645\u503C\u7684\u6570\u7EC4\u5143\u7D20\u3002</p><p>ArrayList \u7684\u4F18\u70B9\u662F\u652F\u6301\u5BF9\u5143\u7D20\u7684\u5FEB\u901F\u968F\u673A\u8BBF\u95EE\uFF0C\u53EF\u4EE5\u6839\u636E\u7D22\u5F15\u5FEB\u901F\u83B7\u53D6\u5230\u5BF9\u5E94\u7684\u5143\u7D20\uFF0CArrayList \u5B9E\u73B0\u4E86 RandomAccess \u63A5\u53E3\uFF0C\u8BE5\u63A5\u53E3\u662F\u4E00\u4E2A\u6807\u5FD7\u63A5\u53E3\uFF0C\u53EF\u7528\u4E8E\u533A\u5206 ArrayList \u548C LinkedList\uFF0C\u5982\u679C\u4E00\u4E2A\u96C6\u5408\u7C7B\u5B9E\u73B0\u4E86 RandomAccess\uFF0C\u90A3\u4E48\u8BE5\u96C6\u5408\u901A\u8FC7\u7D22\u5F15\u904D\u5386\u6BD4\u8FED\u4EE3\u5668\u66F4\u5FEB\u3002</p><blockquote><p>Collections \u7C7B\u7684 binarySearch \u65B9\u6CD5\u6839\u636E <code>list instanceof RandomAccess</code> \u7684\u7ED3\u679C\u6765\u51B3\u5B9A\u91C7\u7528\u7D22\u5F15\u83B7\u53D6\u5143\u7D20\u8FD8\u662F\u91C7\u7528\u8FED\u4EE3\u5668\u3002</p></blockquote><p>ArrayList \u7684\u7F3A\u70B9\u662F\u5728\u5217\u8868\u9996\u90E8\u6216\u4E2D\u95F4\u63D2\u5165\u6216\u5220\u9664\u5143\u7D20\u7684\u901F\u5EA6\u4F1A\u6BD4\u8F83\u6162\uFF0C\u56E0\u4E3A\u9700\u8981\u9891\u7E41\u79FB\u52A8\u5927\u91CF\u5143\u7D20\u7684\u4F4D\u7F6E\u3002</p><h3 id="arraylist-\u548C-arrays-aslist" tabindex="-1"><a class="header-anchor" href="#arraylist-\u548C-arrays-aslist" aria-hidden="true">#</a> ArrayList \u548C Arrays.asList</h3><p>Arrays \u7C7B\u7684 asList \u65B9\u6CD5\u8FD4\u56DE\u7684\u662F\u4E00\u4E2A ArrayList \u5BF9\u8C61\uFF0C\u4F46\u662F\u8FD9\u4E2A ArrayList \u5E76\u4E0D\u662F <code>java.util.ArrayList</code>\uFF0C\u800C\u662F Arrays \u7C7B\u7684\u9759\u6001\u5185\u90E8\u7C7B\uFF0C\u8BE5\u5185\u90E8\u7C7B\u7EE7\u627F\u4E86 AbstractList \u7C7B\u5E76\u5B9E\u73B0\u4E86 RandomAccess \u63A5\u53E3\uFF0C\u4F46\u5B83\u4E0D\u80FD\u76F4\u63A5\u8C03\u7528 add \u65B9\u6CD5\u548C remove \u65B9\u6CD5\uFF0C\u56E0\u4E3A\u5176\u5E76\u672A\u91CD\u5199 AbstractList \u7684 add \u548C remove \u65B9\u6CD5\u3002</p><blockquote><p>\u53EF\u4EE5\u6267\u884C ArrayList(Arrays.asList(array)) \u6765\u751F\u6210 <code>java.util.ArrayList</code> \u5BF9\u8C61\uFF0C\u5176\u4E2D array \u4E3A\u4E00\u4E2A\u6570\u7EC4\u3002</p></blockquote><h3 id="linkedlist-\u7B80\u4ECB" tabindex="-1"><a class="header-anchor" href="#linkedlist-\u7B80\u4ECB" aria-hidden="true">#</a> LinkedList \u7B80\u4ECB</h3><p>LinkedList \u662F\u57FA\u4E8E\u53CC\u5411\u94FE\u8868\u6765\u5B9E\u73B0\u7684\uFF0C\u94FE\u8868\u4E2D\u7684\u6BCF\u4E2A\u8282\u70B9\u90FD\u4F1A\u8BB0\u5F55\u5B83\u7684\u524D\u7F6E\u8282\u70B9\u548C\u540E\u7F6E\u8282\u70B9\u3002\u76F8\u6BD4\u4E8E ArrayList\uFF0CLinkedList \u5728\u5217\u8868\u9996\u90E8\u63D2\u5165\u6216\u5220\u9664\u5143\u7D20\u7684\u901F\u5EA6\u4F1A\u66F4\u5FEB\uFF0C\u56E0\u4E3A\u53EA\u9700\u8981\u4FEE\u6539\u51E0\u4E2A\u6307\u9488\u7684\u503C\u3002\u4F46\u662F\u5982\u679C\u5728\u5217\u8868\u4E2D\u95F4\uFF08\u65E2\u4E0D\u9760\u8FD1\u961F\u9996\u4E5F\u4E0D\u9760\u8FD1\u961F\u5C3E\uFF09\u63D2\u5165\u6216\u5220\u9664\u5143\u7D20\uFF0C\u90A3\u4E48\u5F53\u5143\u7D20\u6570\u91CF\u975E\u5E38\u5927\u65F6\uFF0CLinkedList \u7684\u6267\u884C\u6548\u7387\u4F1A\u975E\u5E38\u4F4E\uFF0C\u751A\u81F3\u53EF\u80FD\u8FDC\u4F4E\u4E8E ArrayList\u3002\u6B64\u5916\uFF0CLinkedList \u4E5F\u4E0D\u652F\u6301\u5BF9\u5143\u7D20\u7684\u5FEB\u901F\u968F\u673A\u8BBF\u95EE\uFF0C\u6BCF\u6B21\u8BBF\u95EE\u5143\u7D20\u65F6\uFF0C\u90FD\u9700\u8981\u904D\u5386\u4E00\u6B21\u94FE\u8868\u3002</p><p>LinkedList \u5B9E\u73B0\u4E86 Deque \u63A5\u53E3\uFF0C\u8FD9\u4F7F\u5F97 LinkedList \u5177\u5907\u4E86\u961F\u5217\u548C\u6808\u7684\u6027\u8D28\u3002\u7531\u4E8E LinkedList \u4E0D\u9700\u8981\u8FDE\u7EED\u7684\u5185\u5B58\u7A7A\u95F4\u8FDB\u884C\u5B58\u50A8\uFF0C\u56E0\u6B64\u5176\u5185\u5B58\u5229\u7528\u7387\u6BD4\u8F83\u9AD8\u3002</p><blockquote><p>\u5982\u679C\u63D2\u5165\u6216\u5220\u9664\u7684\u4F4D\u7F6E\u5728\u5217\u8868\u4E2D\u95F4\uFF0C\u90A3\u4E48\u5F53\u5143\u7D20\u7684\u6570\u91CF\u8F83\u591A\u65F6\uFF0CLinkedList \u6027\u80FD\u7684\u6D88\u8017\u4E3B\u8981\u6765\u81EA\u4E8E\u904D\u5386\u94FE\u8868\u6240\u9700\u8981\u7684\u65F6\u95F4\u5F00\u9500\uFF0CArrayList \u5219\u6765\u81EA\u4E8E\u79FB\u52A8\u5143\u7D20\u7684\u5F00\u9500\uFF0C\u5148\u6BD4\u4E4B\u4E0B\uFF0CArrayList \u7684\u6548\u7387\u66F4\u9AD8\u3002\u5982\u679C\u4F4D\u7F6E\u5728\u5217\u8868\u5C3E\u90E8\uFF0C\u90A3\u4E48\u4E8C\u8005\u7684\u6548\u7387\u5DEE\u4E0D\u591A\uFF0C\u56E0\u4E3A ArrayList \u9700\u8981\u79FB\u52A8\u7684\u5143\u7D20\u8F83\u5C11\uFF0C\u800C LinkedList \u53EF\u4EE5\u4ECE\u5C3E\u90E8\u5F00\u59CB\u5411\u524D\u904D\u5386\u3002\u5982\u679C\u4F4D\u7F6E\u5728\u5217\u8868\u9996\u90E8\uFF0C\u5219 LinkedList \u7684\u6548\u7387\u66F4\u9AD8\u3002</p></blockquote><p><strong>\u5F15\u7533\u95EE\u9898</strong>\uFF1AArrayList \u548C LinkedList \u8C01\u66F4\u5360\u7528\u5185\u5B58\uFF1F</p><p>\u7B54\u6848\u662F\u4E0D\u786E\u5B9A\uFF0C\u56E0\u4E3A LinkedList \u7684 Node \u8282\u70B9\u76F8\u6BD4 ArrayList \u4E2D\u7684\u5355\u4E2A\u5143\u7D20\u66F4\u5360\u7A7A\u95F4\uFF0C\u4F46 ArrayList \u5B58\u5728\u6269\u5BB9\u673A\u5236\uFF0C\u53EF\u80FD\u521A\u521A\u5B8C\u6210\u6269\u5BB9\u5C31\u4E0D\u518D\u6DFB\u52A0\u65B0\u5143\u7D20\u4E86\uFF0C\u90A3\u4E48\u591A\u51FA\u7684\u4E00\u534A\u6570\u7EC4\u5C31\u4F1A\u88AB\u6D6A\u8D39\u6389\u3002</p><h3 id="fail-fast-\u673A\u5236" tabindex="-1"><a class="header-anchor" href="#fail-fast-\u673A\u5236" aria-hidden="true">#</a> fail-fast \u673A\u5236</h3><p>fail-fast \u673A\u5236\u662F\u6240\u6709\u96C6\u5408\u7C7B\uFF08\u5B9E\u73B0 Collection \u63A5\u53E3\u7684\u7C7B\uFF09\u90FD\u6709\u7684\u4E00\u79CD\u9519\u8BEF\u673A\u5236\uFF0C\u8FD9\u4E9B\u7C7B\u901A\u8FC7\u5F15\u5165\u53D8\u91CF modCount \u6765\u8BB0\u5F55\u96C6\u5408\u7ED3\u6784\u6027\u53D8\u5316\u7684\u6B21\u6570\uFF0C\u6240\u6709\u6D89\u53CA\u7ED3\u6784\u53D8\u5316\u7684\u65B9\u6CD5\u90FD\u4F1A\u589E\u52A0 modCount \u7684\u503C\u3002\u5F53\u8FED\u4EE3\u5668\u521D\u59CB\u5316\u65F6\uFF0CmodCount \u4F1A\u88AB\u8D4B\u503C\u7ED9 expectedModCount\uFF0C\u4EE5\u540E\u6BCF\u6B21\u901A\u8FC7\u8FED\u4EE3\u5668\u8BBF\u95EE\u5143\u7D20\u65F6\u90FD\u4F1A\u68C0\u67E5\u6700\u65B0\u7684 modCount \u4E0E expectedModCount \u662F\u5426\u76F8\u7B49\uFF0C\u4E0D\u76F8\u7B49\u7684\u8BDD\u5C31\u4F1A\u629B\u51FA\u5F02\u5E38\u3002\u56E0\u6B64\u5F53\u591A\u4E2A\u7EBF\u7A0B\u540C\u65F6\u64CD\u4F5C\u540C\u4E00\u4E2A\u96C6\u5408\u4E2D\u7684\u5143\u7D20\u65F6\uFF0C\u5C31\u53EF\u80FD\u4EA7\u751F fail-fast \u4E8B\u4EF6\u3002</p><h2 id="map" tabindex="-1"><a class="header-anchor" href="#map" aria-hidden="true">#</a> Map</h2><h3 id="hashmap-\u7B80\u4ECB" tabindex="-1"><a class="header-anchor" href="#hashmap-\u7B80\u4ECB" aria-hidden="true">#</a> HashMap \u7B80\u4ECB</h3><p>HashMap \u662F\u7528\u6765\u5B58\u50A8\u952E\u503C\u5BF9\u7684\u6570\u636E\u7ED3\u6784\uFF0CJDK 1.7 \u7684\u5E95\u5C42\u5B9E\u73B0\u662F\u6570\u7EC4 + \u94FE\u8868\uFF0CJDK 1.8 \u6539\u4E3A\u6570\u7EC4 + \u94FE\u8868/\u7EA2\u9ED1\u6811\uFF0C\u8282\u70B9\u7C7B\u578B\u4E5F\u7531\u539F\u5148\u7684 Entry \u8282\u70B9\u6539\u4E3A\u4E86 Node \u8282\u70B9\uFF0C\u4F46\u65E0\u8BBA\u662F Entry \u8FD8\u662F Node\uFF0C\u5B83\u4EEC\u90FD\u5305\u542B\u56DB\u4E2A\u6210\u5458\u53D8\u91CF\uFF1Akey\u3001value\u3001next \u6307\u9488\u548C hash \u503C\u3002</p><p>HashMap \u4E3B\u8981\u6210\u5458\u53D8\u91CF\u5305\u62EC\u5B58\u50A8\u6570\u636E\u7684 table \u6570\u7EC4\u3001\u5143\u7D20\u6570\u91CF size\u3001\u52A0\u8F7D\u56E0\u5B50 loadFactor\u3002table \u6570\u7EC4\u7684\u6BCF\u4E2A\u4E0B\u6807\u5BF9\u5E94\u4E00\u6761\u94FE\u8868/\u7EA2\u9ED1\u6811\uFF0C\u5B58\u50A8\u5143\u7D20\u65F6\uFF0C\u6839\u636E\u5143\u7D20\u7684 key \u8BA1\u7B97\u54C8\u5E0C\u503C\uFF0C\u5E76\u6839\u636E\u54C8\u5E0C\u503C\u8BA1\u7B97\u6570\u7EC4\u7684\u4E0B\u6807\uFF0C\u6240\u6709\u54C8\u5E0C\u503C\u51B2\u7A81\u7684\u5143\u7D20\u90FD\u4F1A\u88AB\u5B58\u653E\u5230\u540C\u4E00\u4E2A\u54C8\u5E0C\u69FD\u4E2D\uFF0CJDK 1.7 \u4E2D\u91C7\u7528\u5934\u63D2\u6CD5\u7684\u65B9\u5F0F\u5B58\u50A8\u5143\u7D20\uFF0CJDK 1.8 \u6539\u4E3A\u4E86\u5C3E\u63D2\u6CD5\uFF0C\u5E76\u4E14\u540C\u4E00\u4E2A\u54C8\u5E0C\u69FD\u4E2D\u7684\u5143\u7D20\u8FBE\u5230\u4E00\u5B9A\u9608\u503C\u540E\u4F1A\u5C06\u94FE\u8868\u8F6C\u5316\u4E3A\u7EA2\u9ED1\u6811\u3002\u54C8\u5E0C\u51B2\u7A81\u4F1A\u5F71\u54CD HashMap \u67E5\u8BE2\u7684\u6548\u7387\uFF0C\u6240\u4EE5 key \u7684 hash \u503C\u8981\u5C3D\u53EF\u80FD\u5206\u6563\u3002</p><p>HashMap \u9ED8\u8BA4\u521D\u59CB\u5316\u5BB9\u91CF\u4E3A 16\uFF0C\u6269\u5BB9\u5BB9\u91CF\u5FC5\u987B\u662F 2 \u7684\u5E42\u6B21\u65B9\u3001\u6700\u5927\u5BB9\u91CF\u4E3A 1&lt;&lt; 30 \u3001\u9ED8\u8BA4\u52A0\u8F7D\u56E0\u5B50\u4E3A 0.75\u3002</p><h3 id="hashmap-\u7684\u4E3B\u8981\u65B9\u6CD5-\u91CD\u70B9" tabindex="-1"><a class="header-anchor" href="#hashmap-\u7684\u4E3B\u8981\u65B9\u6CD5-\u91CD\u70B9" aria-hidden="true">#</a> HashMap \u7684\u4E3B\u8981\u65B9\u6CD5\uFF08\u91CD\u70B9\uFF09</h3><h3 id="linkedhashmap" tabindex="-1"><a class="header-anchor" href="#linkedhashmap" aria-hidden="true">#</a> LinkedHashMap</h3><h3 id="treemap" tabindex="-1"><a class="header-anchor" href="#treemap" aria-hidden="true">#</a> TreeMap</h3><h2 id="set" tabindex="-1"><a class="header-anchor" href="#set" aria-hidden="true">#</a> Set</h2>',27),d=[s];function h(n,o){return e(),r("div",null,d)}var l=a(i,[["render",h],["__file","Java\u96C6\u5408.html.vue"]]);export{l as default};
